export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>();
  for (const [x, y] of cells) {
    liveSet.add(key(x, y));
  }

  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const k = key(nx, ny);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const isAlive = liveSet.has(k);
    if (isAlive && (count === 2 || count === 3)) {
      result.push(parseKey(k));
    } else if (!isAlive && count === 3) {
      result.push(parseKey(k));
    }
  }

  // Also include live cells with 0 neighbors? They would die anyway (underpopulation).
  // No need - cells with 0 neighbors have count undefined in neighborCounts but
  // they are alive with 0 neighbors so they die per rule 1.

  return result;
}

function key(x: number, y: number): string {
  return `${x},${y}`;
}

function parseKey(k: string): Cell {
  const [x, y] = k.split(',').map(Number);
  return [x, y];
}

